def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    from pptx.util import Inches

    try:
        ppt_modified = Presentation(modified_ppt_path)

        if len(ppt_modified.slides) == 0:
            return "No slides found in presentation", 0.0

        modified_slide = ppt_modified.slides[0]
        slide_width = ppt_modified.slide_width
        slide_height = ppt_modified.slide_height

        # Look for shapes that could be background rectangles
        # They should be large enough to cover most/all of the slide
        overlay_shapes = []

        for shape in modified_slide.shapes:
            if hasattr(shape, 'width') and hasattr(shape, 'height'):
                shape_width = shape.width
                shape_height = shape.height

                # Check if shape is large enough to be a background overlay
                # Should cover at least 80% of slide area
                width_ratio = shape_width / slide_width
                height_ratio = shape_height / slide_height

                if width_ratio >= 0.8 and height_ratio >= 0.8:
                    overlay_shapes.append(shape)

        if len(overlay_shapes) > 0:
            return f"Found {len(overlay_shapes)} shape(s) that appear to be positioned as background overlays", 1.0
        else:
            return "No shapes found that are positioned/sized as background overlays", 0.0

    except Exception as e:
        return f"Error checking shape positioning: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
