    original_screenshot = None
    modified_screenshot = None

    for screenshot in original_ppt_screenshots:
        if screenshot.slide_number == 1:
            original_screenshot = screenshot
            break

    for screenshot in modified_ppt_screenshots:
        if screenshot.slide_number == 1:
            modified_screenshot = screenshot
            break

    if not original_screenshot or not modified_screenshot:
        return "Could not find title slide screenshots", 0.0

    prompt = '''Compare these two slides (before and after). 

The task was to change the background color of the title slide to light blue by adding a rectangular overlay.

Please analyze:
1. Does the modified slide (after) have a light blue background color and is there a clear difference in background color between the before and after images?
2. Is the background color transparent enough to see through to the original slide content?

Respond with an overall single response of either "YES" if the background appears light blue and is transparent enough, "PARTIAL" if it is light blue but not transparent enough, or "NO" if neither of the above, followed by a brief explanation.'''

    try:
        response = vlm_call(prompt, [original_screenshot.image_path, modified_screenshot.image_path], temperature=0.3)

        if  'YES' in response:
            return f"Background color appears light blue and is transparent enough: {response}", 1.0
        elif 'PARTIAL' in response:
            return f"Background color appears light blue but not transparent enough: {response}", 0.2
        else:
            return f"Background color does not appear light blue and is not transparent enough: {response}", 0.0

    except Exception as e:
        return f"Error analyzing background color: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        ppt_original = Presentation(original_ppt_path)
        ppt_modified = Presentation(modified_ppt_path)

        original_slide_count = len(ppt_original.slides)
        modified_slide_count = len(ppt_modified.slides)

        # Check if slide count changed
        if original_slide_count != modified_slide_count:
            return f"Slide count changed from {original_slide_count} to {modified_slide_count}", 0.0

        # Check if any non-title slides were modified
        non_title_modifications = 0

        for old_slide, new_slide in ppt_diff.modified_slides:
            if old_slide.slide_number != 1 and new_slide.slide_number != 1:
                non_title_modifications += 1

        # Also check for added/removed slides
        if len(ppt_diff.added_slides) > 0 or len(ppt_diff.removed_slides) > 0:
            return f"Slides were added or removed: {len(ppt_diff.added_slides)} added, {len(ppt_diff.removed_slides)} removed", 0.0

        if non_title_modifications == 0:
            return "No extraneous changes detected to other slides", 1.0
        else:
            return f"Found {non_title_modifications} modifications to non-title slides", 0.0

    except Exception as e:
        return f"Error checking for extraneous changes: {str(e)}", 0.5

def compute_score() -> tuple[str, float]:
    # Use visual analysis to check if original content is still present
    original_screenshot = None
    modified_screenshot = None

    for screenshot in original_ppt_screenshots:
        if screenshot.slide_number == 1:
            original_screenshot = screenshot
            break

    for screenshot in modified_ppt_screenshots:
        if screenshot.slide_number == 1:
            modified_screenshot = screenshot
            break

    if not original_screenshot or not modified_screenshot:
        return "Could not find title slide screenshots for content analysis", 0.5

    prompt = '''Compare these two slides (before and after). The task was only to add a light blue background overlay.

Please analyze:
1. Is all the original text content still present and readable in the modified slide?
2. Are any images, logos, or other elements from the original slide still visible?
3. Does it appear that only a background color change was made, without removing or altering existing content?

Respond with "PRESERVED" if the original content appears to be maintained, or "ALTERED" if content seems to have been removed or significantly changed.'''

    try:
        response = vlm_call(prompt, [original_screenshot.image_path, modified_screenshot.image_path], temperature=0.3)

        if 'PRESERVED' in response.upper():
            return f"Original slide content appears preserved: {response}", 1.0
        else:
            return f"Original slide content may have been altered: {response}", 0.3

    except Exception as e:
        return f"Error analyzing content preservation: {str(e)}", 0.5
